// Pardle service worker. Lives at /sw.js so it's same-origin and can
// intercept push events for the whole pardle.app scope.

self.addEventListener("push", (event) => {
  if (!event.data) return;
  let payload;
  try {
    payload = event.data.json();
  } catch {
    payload = { title: "Pardle", body: event.data.text() };
  }
  const title = payload.title || "Pardle";
  const options = {
    body: payload.body || "",
    // Next.js auto-serves the dynamic 180x180 PNG generated by
    // app/apple-icon.tsx at /apple-icon — used as both the
    // notification banner icon and the Android status-bar badge.
    // Was /icon-192.png which never existed in /public.
    icon: payload.icon || "/apple-icon",
    badge: payload.badge || "/apple-icon",
    tag: payload.tag,
    data: { url: payload.url || "/" },
    requireInteraction: false,
  };
  event.waitUntil(self.registration.showNotification(title, options));
});

self.addEventListener("notificationclick", (event) => {
  event.notification.close();
  const targetUrl = (event.notification.data && event.notification.data.url) || "/";
  event.waitUntil(
    self.clients
      .matchAll({ type: "window", includeUncontrolled: true })
      .then((clientsArr) => {
        // If a tab is already on Pardle, focus + navigate to the target.
        for (const client of clientsArr) {
          if ("focus" in client) {
            const u = new URL(client.url);
            if (u.origin === self.location.origin) {
              client.focus();
              if ("navigate" in client) {
                client.navigate(targetUrl);
              }
              return;
            }
          }
        }
        if (self.clients.openWindow) {
          return self.clients.openWindow(targetUrl);
        }
      }),
  );
});
